  AND (ISNULL(@dept_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.dept_nm)) COLLATE DATABASE_DEFAULT) + N',', @dept_name_LIST COLLATE DATABASE_DEFAULT) > 0)
  AND (ISNULL(@common_tp_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(B.common_tp_nm)) COLLATE DATABASE_DEFAULT) + N',', @common_tp_nm_LIST COLLATE DATABASE_DEFAULT) > 0);

DECLARE @CONST_TP_GRP NVARCHAR(MAX) = N'관계형성,기회창출';
DECLARE @CONST_EXCLUDE_NAME NVARCHAR(MAX) = N'고객지원팀,TOYOTA YM';
DECLARE @CONST_EXCLUDE_USER NVARCHAR(MAX) = N'DM5103,DM9999,JB30007,JB30016,KMKS176,KMKS999,JB30067';
DECLARE @CONST_FACADE_EXCLUDE NVARCHAR(50) = N'창구SC';

DECLARE @YearMonth NVARCHAR(50) = N'2026-04';
DECLARE @brand NVARCHAR(MAX) = N'LEXUS';
DECLARE @active_yn NVARCHAR(MAX) = N'재직';
DECLARE @dealer_nm NVARCHAR(MAX) = N'렉서스 강남,렉서스 용산';
DECLARE @group_name NVARCHAR(MAX) = N'렉서스 강남,렉서스 의정부';
DECLARE @dept_name NVARCHAR(MAX) = N'';
DECLARE @common_tp_nm NVARCHAR(MAX) = N'';

DECLARE @MonthStart DATE = CAST(@YearMonth + N'-01' AS DATE);
DECLARE @MaxDate DATE = EOMONTH(@MonthStart);

DECLARE @CONST_TP_GRP_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@CONST_TP_GRP, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @CONST_EXCLUDE_NAME_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@CONST_EXCLUDE_NAME, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @CONST_EXCLUDE_USER_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@CONST_EXCLUDE_USER, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @brand_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@brand, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @active_yn_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@active_yn, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @dealer_nm_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@dealer_nm, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @group_name_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@group_name, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @dept_name_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@dept_name, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @common_tp_nm_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@common_tp_nm, N''), N', ', N','), N' ,', N',') + N',';

;WITH filtered_dates AS (
    SELECT Date
    FROM ktws.DIM_CALENDAR_KTWS
    WHERE Date >= @MonthStart AND Date < DATEADD(DAY, 1, @MaxDate)
),
filtered_users AS (
    SELECT D.sc_key
    FROM ktws.DIM_MNG_USER AS D
    INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key
    WHERE (D.facade_sc_yn IS NULL OR D.facade_sc_yn COLLATE DATABASE_DEFAULT <> @CONST_FACADE_EXCLUDE COLLATE DATABASE_DEFAULT)
    AND (D.name IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.name)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_NAME_LIST COLLATE DATABASE_DEFAULT) = 0)
    AND (D.user_id IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.user_id)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_USER_LIST COLLATE DATABASE_DEFAULT) = 0)
    AND (ISNULL(@active_yn, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.active_yn)) COLLATE DATABASE_DEFAULT) + N',', @active_yn_LIST COLLATE DATABASE_DEFAULT) > 0)
    AND (ISNULL(@dealer_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(E.dealer_nm)) COLLATE DATABASE_DEFAULT) + N',', @dealer_nm_LIST COLLATE DATABASE_DEFAULT) > 0)
    AND (ISNULL(@brand, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.BRAND)) COLLATE DATABASE_DEFAULT) + N',', @brand_LIST COLLATE DATABASE_DEFAULT) > 0)
    AND (ISNULL(@group_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.group_name)) COLLATE DATABASE_DEFAULT) + N',', @group_name_LIST COLLATE DATABASE_DEFAULT) > 0)
    AND (ISNULL(@dept_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.dept_nm)) COLLATE DATABASE_DEFAULT) + N',', @dept_name_LIST COLLATE DATABASE_DEFAULT) > 0)
),
filtered_types AS (
    SELECT B.tp_key
    FROM ktws.DIM_CRM_ACT_TYPE AS B
    WHERE 1 = 1
    AND CHARINDEX(N',' + (LTRIM(RTRIM(B.tp_grp_1)) COLLATE DATABASE_DEFAULT) + N',', @CONST_TP_GRP_LIST COLLATE DATABASE_DEFAULT) > 0
    AND (ISNULL(@common_tp_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(B.common_tp_nm)) COLLATE DATABASE_DEFAULT) + N',', @common_tp_nm_LIST COLLATE DATABASE_DEFAULT) > 0)
),
target_cnt AS (
    SELECT SUM(A.target_cnt) AS cnt
    FROM ktws.FCT_CRM_TARGET_D AS A
    INNER JOIN filtered_dates AS C ON A.daily_dt = C.Date
    INNER JOIN filtered_users AS D ON A.sc_key = D.sc_key
    INNER JOIN filtered_types AS B ON A.type_cd = B.tp_key
),
actual_cnt AS (
    SELECT SUM(A.actual_cnt) AS cnt
    FROM ktws.FCT_ACTIVITY_v2 AS A
    INNER JOIN filtered_dates AS C ON A.act_dt_fr = C.Date
    INNER JOIN filtered_users AS D ON A.sc_key = D.sc_key
    INNER JOIN filtered_types AS B ON A.tp_key = B.tp_key
)
SELECT
    FORMAT(CAST(A.cnt AS FLOAT) / NULLIF(T.cnt, 0), '0%') AS Percentage
FROM target_cnt AS T
CROSS JOIN actual_cnt AS A;

DECLARE @CONST_TP_GRP NVARCHAR(MAX) = N'관계형성,기회창출';
DECLARE @CONST_EXCLUDE_NAME NVARCHAR(MAX) = N'고객지원팀,TOYOTA YM';
DECLARE @CONST_EXCLUDE_USER NVARCHAR(MAX) = N'DM5103,DM9999,JB30007,JB30016,KMKS176,KMKS999,JB30067';
DECLARE @CONST_FACADE_EXCLUDE NVARCHAR(50) = N'창구SC';

DECLARE @YearMonth NVARCHAR(50) = N'2026-04';
DECLARE @brand NVARCHAR(MAX) = N'LEXUS';
DECLARE @active_yn NVARCHAR(MAX) = N'재직';
DECLARE @dealer_nm NVARCHAR(MAX) = N'렉서스 강남,렉서스 용산';
DECLARE @group_name NVARCHAR(MAX) = N'렉서스 강남,렉서스 의정부';
DECLARE @dept_name NVARCHAR(MAX) = N'';
DECLARE @common_tp_nm NVARCHAR(MAX) = N'';

DECLARE @MonthStart DATE = CAST(@YearMonth + N'-01' AS DATE);
DECLARE @MaxDate DATE = EOMONTH(@MonthStart);

DECLARE @CONST_TP_GRP_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@CONST_TP_GRP, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @CONST_EXCLUDE_NAME_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@CONST_EXCLUDE_NAME, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @CONST_EXCLUDE_USER_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@CONST_EXCLUDE_USER, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @brand_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@brand, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @active_yn_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@active_yn, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @dealer_nm_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@dealer_nm, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @group_name_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@group_name, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @dept_name_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@dept_name, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @common_tp_nm_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@common_tp_nm, N''), N', ', N','), N' ,', N',') + N',';

WITH lead_cnt AS (
SELECT COUNT(DISTINCT G.lead_key) AS cnt
FROM ktws.FCT_LEAD AS G
       INNER JOIN ktws.DIM_MNG_USER AS D ON G.cl_sc_key = D.sc_key
       INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key
WHERE G.lead_reg_dt >= @MonthStart AND G.lead_reg_dt < DATEADD(DAY, 1, @MaxDate)
AND G.lead_key IN (SELECT ACT.lead_key
                   FROM ktws.FCT_ACTIVITY_v2 AS ACT
                            INNER JOIN ktws.DIM_CRM_ACT_TYPE AS ACT_B ON ACT.tp_key = ACT_B.tp_key
                            INNER JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS ACT_F
                                       ON ACT_B.common_tp_nm = ACT_F.common_tp_nm
                   WHERE ACT_B.tp_grp_1 IN (SELECT value FROM STRING_SPLIT(@CONST_TP_GRP, ','))
                     AND ACT.act_result <> N'부재중'
                     AND (ISNULL(@common_tp_nm, N'') = N'' OR
                          CHARINDEX(N',' + (LTRIM(RTRIM(ACT_F.common_tp_nm)) COLLATE DATABASE_DEFAULT) + N',',
                                    @common_tp_nm_LIST COLLATE DATABASE_DEFAULT) > 0))
AND (G.close_dt > EOMONTH(CAST(@YearMonth + N'-01' AS DATE)) OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)

  AND (D.facade_sc_yn IS NULL OR D.facade_sc_yn COLLATE DATABASE_DEFAULT <> @CONST_FACADE_EXCLUDE COLLATE DATABASE_DEFAULT)
  AND (D.name IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.name)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_NAME_LIST COLLATE DATABASE_DEFAULT) = 0)
  AND (D.user_id IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.user_id)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_USER_LIST COLLATE DATABASE_DEFAULT) = 0)
  AND (ISNULL(@active_yn, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.active_yn)) COLLATE DATABASE_DEFAULT) + N',', @active_yn_LIST COLLATE DATABASE_DEFAULT) > 0)
  AND (ISNULL(@dealer_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(E.dealer_nm)) COLLATE DATABASE_DEFAULT) + N',', @dealer_nm_LIST COLLATE DATABASE_DEFAULT) > 0)
  AND (ISNULL(@brand, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.BRAND)) COLLATE DATABASE_DEFAULT) + N',', @brand_LIST COLLATE DATABASE_DEFAULT) > 0)
  AND (ISNULL(@group_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.group_name)) COLLATE DATABASE_DEFAULT) + N',', @group_name_LIST COLLATE DATABASE_DEFAULT) > 0)
  AND (ISNULL(@dept_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.dept_nm)) COLLATE DATABASE_DEFAULT) + N',', @dept_name_LIST COLLATE DATABASE_DEFAULT) > 0)
),
act_cnt AS (
SELECT SUM(A.actual_cnt) AS cnt
FROM ktws.FCT_ACTIVITY_v2 AS A
        INNER JOIN ktws.DIM_CRM_ACT_TYPE AS B ON A.tp_key = B.tp_key
        INNER JOIN ktws.DIM_CALENDAR_KTWS AS C ON A.act_dt_fr = C.Date
        INNER JOIN ktws.DIM_MNG_USER AS D ON A.sc_key = D.sc_key
        INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key
        INNER JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS F ON B.common_tp_nm = F.common_tp_nm
WHERE
  CHARINDEX(N',' + (LTRIM(RTRIM(B.tp_grp_1)) COLLATE DATABASE_DEFAULT) + N',', @CONST_TP_GRP_LIST COLLATE DATABASE_DEFAULT) > 0
  AND (D.facade_sc_yn IS NULL OR D.facade_sc_yn COLLATE DATABASE_DEFAULT <> @CONST_FACADE_EXCLUDE COLLATE DATABASE_DEFAULT)
  AND (D.name IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.name)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_NAME_LIST COLLATE DATABASE_DEFAULT) = 0)
  AND (D.user_id IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.user_id)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_USER_LIST COLLATE DATABASE_DEFAULT) = 0)

  AND A.act_dt_fr >= @MonthStart AND A.act_dt_fr < DATEADD(DAY, 1, @MaxDate)
  AND (ISNULL(@active_yn, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.active_yn)) COLLATE DATABASE_DEFAULT) + N',', @active_yn_LIST COLLATE DATABASE_DEFAULT) > 0)
  AND (ISNULL(@dealer_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(E.dealer_nm)) COLLATE DATABASE_DEFAULT) + N',', @dealer_nm_LIST COLLATE DATABASE_DEFAULT) > 0)
