    INNER JOIN mtd_dates AS DT ON G.lead_reg_dt = DT.[Date]
    INNER JOIN filtered_users AS U ON G.cl_sc_key = U.sc_key
    INNER JOIN testdrive_act_grp AS A ON G.lead_key = A.lead_key
    WHERE G.close_dt > @RefDate OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL
),
testdrive_cnt AS (
    SELECT COUNT(DISTINCT ACT.lead_key) AS cnt
    FROM ktws.FCT_ACTIVITY_v2 AS ACT
    INNER JOIN mtd_dates AS DT ON ACT.act_dt_fr = DT.[Date]
    INNER JOIN filtered_users AS U ON ACT.sc_key = U.sc_key
    INNER JOIN testdrive_lead_grp AS L ON ACT.lead_key = L.lead_key
    WHERE ACT.act_tp = 'P113'
      AND ACT.act_result = '시승완료'
      AND ACT.lead_key IS NOT NULL
),
lead_cnt AS (
    SELECT COUNT(DISTINCT G.lead_key) AS cnt
    FROM ktws.FCT_LEAD AS G
    INNER JOIN ktws.DIM_MNG_USER AS D ON G.cl_sc_key = D.sc_key
    INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key
    INNER JOIN ktws.DIM_CALENDAR_KTWS AS H ON G.lead_reg_dt = H.[Date]
