    FROM ktws.DIM_MNG_USER AS D
    INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key
    WHERE (D.facade_sc_yn IS NULL OR D.facade_sc_yn COLLATE DATABASE_DEFAULT <> @CONST_FACADE_EXCLUDE COLLATE DATABASE_DEFAULT)
      AND (D.name IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.name)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_NAME_LIST COLLATE DATABASE_DEFAULT) = 0)
      AND (D.user_id IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.user_id)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_USER_LIST COLLATE DATABASE_DEFAULT) = 0)
      AND (ISNULL(@active_yn, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.active_yn)) COLLATE DATABASE_DEFAULT) + N',', @active_yn_LIST COLLATE DATABASE_DEFAULT) > 0)
      AND (ISNULL(@dealer_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(E.dealer_nm)) COLLATE DATABASE_DEFAULT) + N',', @dealer_nm_LIST COLLATE DATABASE_DEFAULT) > 0)
      AND (ISNULL(@brand, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.BRAND)) COLLATE DATABASE_DEFAULT) + N',', @brand_LIST COLLATE DATABASE_DEFAULT) > 0)
      AND (ISNULL(@group_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.group_name)) COLLATE DATABASE_DEFAULT) + N',', @group_name_LIST COLLATE DATABASE_DEFAULT) > 0)
      AND (ISNULL(@dept_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.dept_nm)) COLLATE DATABASE_DEFAULT) + N',', @dept_name_LIST COLLATE DATABASE_DEFAULT) > 0)
),
activity_leads AS (
    SELECT DISTINCT ACT.lead_key
    FROM ktws.FCT_ACTIVITY_v2 AS ACT
    INNER JOIN filtered_users AS U ON ACT.sc_key = U.sc_key
    INNER JOIN ktws.DIM_CRM_ACT_TYPE AS B ON ACT.tp_key = B.tp_key
    LEFT JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS F ON B.common_tp_nm = F.common_tp_nm
    WHERE ACT.act_dt_fr >= @MonthStart AND ACT.act_dt_fr < DATEADD(DAY, 1, @MaxDate)
      AND CHARINDEX(N',' + (LTRIM(RTRIM(B.tp_grp_1)) COLLATE DATABASE_DEFAULT) + N',', @CONST_TP_GRP_LIST COLLATE DATABASE_DEFAULT) > 0
      AND ACT.act_result <> N'부재중'
      AND ACT.lead_key IS NOT NULL
      AND (ISNULL(@common_tp_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(F.common_tp_nm)) COLLATE DATABASE_DEFAULT) + N',', @common_tp_nm_LIST COLLATE DATABASE_DEFAULT) > 0)
),
lead_pool AS (
    SELECT DISTINCT G.lead_key
    FROM ktws.FCT_LEAD AS G
    INNER JOIN filtered_users AS U ON G.cl_sc_key = U.sc_key
    INNER JOIN activity_leads AS A ON G.lead_key = A.lead_key
    WHERE G.lead_reg_dt >= @MonthStart AND G.lead_reg_dt < DATEADD(DAY, 1, @MaxDate)
      AND G.lead_key IS NOT NULL
      AND G.td_yn = 'Y'
      AND (G.close_dt > @RefDate OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)
)
SELECT COALESCE(SUM(I.cnt), 0) AS contract_cnt
FROM ktws.FCT_CONTRACT_KTWS AS I
INNER JOIN filtered_users AS U ON I.cn_sc_key = U.sc_key
INNER JOIN lead_pool AS L ON I.lead_key = L.lead_key
WHERE I.contract_dt >= @MonthStart AND I.contract_dt < DATEADD(DAY, 1, @MaxDate);

DECLARE @CONST_TP_GRP NVARCHAR(MAX) = N'관계형성,기회창출';
DECLARE @CONST_EXCLUDE_NAME NVARCHAR(MAX) = N'고객지원팀,TOYOTA YM';
DECLARE @CONST_EXCLUDE_USER NVARCHAR(MAX) = N'DM5103,DM9999,JB30007,JB30016,KMKS176,KMKS999,JB30067';
DECLARE @CONST_FACADE_EXCLUDE NVARCHAR(50) = N'창구SC';

DECLARE @YearMonth NVARCHAR(50) = N'2026-04';
DECLARE @brand NVARCHAR(MAX) = N'';
DECLARE @active_yn NVARCHAR(MAX) = N'';
DECLARE @dealer_nm NVARCHAR(MAX) = N'';
DECLARE @group_name NVARCHAR(MAX) = N'';
DECLARE @dept_name NVARCHAR(MAX) = N'';
DECLARE @common_tp_nm NVARCHAR(MAX) = N'';

DECLARE @MonthStart DATE = CAST(@YearMonth + N'-01' AS DATE);
DECLARE @MaxDate DATE = EOMONTH(@MonthStart);

DECLARE @CONST_EXCLUDE_NAME_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@CONST_EXCLUDE_NAME, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @CONST_EXCLUDE_USER_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@CONST_EXCLUDE_USER, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @brand_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@brand, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @active_yn_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@active_yn, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @dealer_nm_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@dealer_nm, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @group_name_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@group_name, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @dept_name_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@dept_name, N''), N', ', N','), N' ,', N',') + N',';
DECLARE @common_tp_nm_LIST NVARCHAR(MAX) = N',' + REPLACE(REPLACE(ISNULL(@common_tp_nm, N''), N', ', N','), N' ,', N',') + N',';

;WITH filtered_users AS (
    SELECT DISTINCT D.sc_key
    FROM ktws.DIM_MNG_USER AS D
    INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key
    WHERE (D.facade_sc_yn IS NULL OR D.facade_sc_yn COLLATE DATABASE_DEFAULT <> @CONST_FACADE_EXCLUDE COLLATE DATABASE_DEFAULT)
      AND (D.name IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.name)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_NAME_LIST COLLATE DATABASE_DEFAULT) = 0)
      AND (D.user_id IS NULL OR CHARINDEX(N',' + (LTRIM(RTRIM(D.user_id)) COLLATE DATABASE_DEFAULT) + N',', @CONST_EXCLUDE_USER_LIST COLLATE DATABASE_DEFAULT) = 0)
      AND (ISNULL(@active_yn, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.active_yn)) COLLATE DATABASE_DEFAULT) + N',', @active_yn_LIST COLLATE DATABASE_DEFAULT) > 0)
      AND (ISNULL(@dealer_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(E.dealer_nm)) COLLATE DATABASE_DEFAULT) + N',', @dealer_nm_LIST COLLATE DATABASE_DEFAULT) > 0)
      AND (ISNULL(@brand, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.BRAND)) COLLATE DATABASE_DEFAULT) + N',', @brand_LIST COLLATE DATABASE_DEFAULT) > 0)
      AND (ISNULL(@group_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.group_name)) COLLATE DATABASE_DEFAULT) + N',', @group_name_LIST COLLATE DATABASE_DEFAULT) > 0)
      AND (ISNULL(@dept_name, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(D.dept_nm)) COLLATE DATABASE_DEFAULT) + N',', @dept_name_LIST COLLATE DATABASE_DEFAULT) > 0)
),
lead_set AS (
    SELECT DISTINCT G.lead_key
    FROM ktws.FCT_LEAD AS G
    INNER JOIN filtered_users AS U ON G.cl_sc_key = U.sc_key
    LEFT JOIN ktws.DIM_CRM_ACT_TYPE AS B ON G.tp_key = B.tp_key
    LEFT JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS F ON B.common_tp_nm = F.common_tp_nm
    WHERE G.lead_key IS NOT NULL
      AND (ISNULL(@common_tp_nm, N'') = N'' OR CHARINDEX(N',' + (LTRIM(RTRIM(F.common_tp_nm)) COLLATE DATABASE_DEFAULT) + N',', @common_tp_nm_LIST COLLATE DATABASE_DEFAULT) > 0)
),
filtered_leads AS (
    SELECT DISTINCT ACT.lead_key
    FROM ktws.FCT_ACTIVITY_v2 AS ACT
    INNER JOIN filtered_users AS U ON ACT.sc_key = U.sc_key
    INNER JOIN lead_set AS L ON ACT.lead_key = L.lead_key
    WHERE ACT.act_dt_fr >= @MonthStart AND ACT.act_dt_fr < DATEADD(DAY, 1, @MaxDate)
      AND ACT.act_tp = N'P113'
      AND ACT.act_result = N'시승완료'
      AND ACT.lead_key IS NOT NULL
      -- ALL('ktws DIM_CRM_ACT_TYPE') 때문에 여기에는 common_tp_nm / tp_grp 필터 걸면 안 됨
)
SELECT COALESCE(SUM(I.cnt), 0) AS contract_cnt
FROM ktws.FCT_CONTRACT_KTWS AS I
INNER JOIN filtered_users AS U ON I.cn_sc_key = U.sc_key
INNER JOIN filtered_leads AS L ON I.lead_key = L.lead_key
WHERE I.contract_dt >= @MonthStart AND I.contract_dt < DATEADD(DAY, 1, @MaxDate);

/* ===== 기간 ===== */
DECLARE @year INT = 2026;
DECLARE @month INT = 4;
DECLARE @day INT = NULL; -- NULL이면 월말 기준 MTD, 특정 일자면 해당 일자까지 MTD

DECLARE @month_start DATE = DATEFROMPARTS(@year, @month, 1);
DECLARE @as_of_date DATE = CASE WHEN @day IS NULL THEN EOMONTH(@month_start) ELSE DATEFROMPARTS(@year, @month, @day) END;
DECLARE @ref_date DATE = @as_of_date;

/* ===== 슬라이서: NULL 또는 ''이면 전체 ===== */
DECLARE @brand NVARCHAR(MAX) = N'';
DECLARE @dealer_nm NVARCHAR(MAX) = N'';
DECLARE @group_name NVARCHAR(MAX) = N'';
DECLARE @dept_nm NVARCHAR(MAX) = N'';
DECLARE @active_yn NVARCHAR(MAX) = N'';
DECLARE @sc_name NVARCHAR(MAX) = N'ALL';
DECLARE @common_tp_nm NVARCHAR(MAX) = NULL;

/* ===== 퍼널 페이지 고정 조건 ===== */
DECLARE @tp_grp_1 NVARCHAR(MAX) = N'관계형성,기회창출';
DECLARE @exclude_facade NVARCHAR(50) = N'창구SC';
DECLARE @exclude_name NVARCHAR(MAX) = N'고객지원팀,TOYOTA YM';
DECLARE @exclude_user_ids NVARCHAR(MAX) = N'DM5103,DM9999,JB30007,JB30016,KMKS176,KMKS999,JB30067';

DECLARE @sc_filter NVARCHAR(MAX) = CASE WHEN @sc_name IS NULL OR LTRIM(RTRIM(@sc_name)) = N'' OR UPPER(LTRIM(RTRIM(@sc_name))) = N'ALL' THEN NULL ELSE @sc_name END;

SET NOCOUNT ON;

/*
  실행 계획 생성 오류 방지용 수정본입니다.
  원본 CTE 계산식은 유지하고, 각 CTE를 #temp 테이블로 한 번씩 물리화합니다.
  Fabric Warehouse/Lakehouse SQL용: CREATE INDEX 없이 #temp 물리화만 사용합니다.
*/
DROP TABLE IF EXISTS #metric_raw;
DROP TABLE IF EXISTS #contract_td_total_count;
DROP TABLE IF EXISTS #contract_td_activity_count;
DROP TABLE IF EXISTS #contract_td_lead_set;
DROP TABLE IF EXISTS #td_target;
DROP TABLE IF EXISTS #td_total_actual_sum;
DROP TABLE IF EXISTS #td_total_lead_distinct;
DROP TABLE IF EXISTS #td_completed_total_lead_set;
DROP TABLE IF EXISTS #lead_set_all_calendar;
DROP TABLE IF EXISTS #td_form_without_cancel;
DROP TABLE IF EXISTS #td_completed_lead_match;
DROP TABLE IF EXISTS #td_lead_set;
DROP TABLE IF EXISTS #td_activity_candidate;
DROP TABLE IF EXISTS #contract_progress_count;
DROP TABLE IF EXISTS #contract_progress_lead_set;
DROP TABLE IF EXISTS #contract_progress_activity_candidate;
DROP TABLE IF EXISTS #contract_target;
DROP TABLE IF EXISTS #contract_total_count;
DROP TABLE IF EXISTS #contract_activity_count;
DROP TABLE IF EXISTS #lead_target;
DROP TABLE IF EXISTS #lead_total_count;
DROP TABLE IF EXISTS #lead_activity_count;
DROP TABLE IF EXISTS #lead_activity_set;
DROP TABLE IF EXISTS #lead_activity_candidate;
DROP TABLE IF EXISTS #activity_target;
DROP TABLE IF EXISTS #activity_actual;
DROP TABLE IF EXISTS #scope_type;
DROP TABLE IF EXISTS #scope_user;
DROP TABLE IF EXISTS #scope;
DROP TABLE IF EXISTS #scope_seed;
DROP TABLE IF EXISTS #valid_type;
DROP TABLE IF EXISTS #valid_group;
DROP TABLE IF EXISTS #valid_common_type;
DROP TABLE IF EXISTS #valid_user;

/* ===== #valid_user ===== */
SELECT *
INTO #valid_user
FROM (
SELECT DISTINCT U.sc_key, U.BRAND AS brand_nm, D.dealer_nm, U.group_name, U.dept_nm, U.name AS sc_name
    FROM ktws.DIM_MNG_USER AS U
    LEFT JOIN ktws.DIM_MNG_DEALER AS D ON U.dealer_key = D.dealer_key
    WHERE ISNULL(U.facade_sc_yn, N'') COLLATE DATABASE_DEFAULT <> @exclude_facade COLLATE DATABASE_DEFAULT
      AND NOT EXISTS (SELECT 1 FROM STRING_SPLIT(@exclude_name, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = U.name COLLATE DATABASE_DEFAULT)
      AND NOT EXISTS (SELECT 1 FROM STRING_SPLIT(@exclude_user_ids, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = U.user_id COLLATE DATABASE_DEFAULT)
      AND (NULLIF(LTRIM(RTRIM(@brand)), N'') IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@brand, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = U.BRAND COLLATE DATABASE_DEFAULT))
      AND (NULLIF(LTRIM(RTRIM(@dealer_nm)), N'') IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@dealer_nm, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = D.dealer_nm COLLATE DATABASE_DEFAULT))
      AND (NULLIF(LTRIM(RTRIM(@group_name)), N'') IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@group_name, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = U.group_name COLLATE DATABASE_DEFAULT))
      AND (NULLIF(LTRIM(RTRIM(@dept_nm)), N'') IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@dept_nm, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = U.dept_nm COLLATE DATABASE_DEFAULT))
      AND (NULLIF(LTRIM(RTRIM(@active_yn)), N'') IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@active_yn, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = U.active_yn COLLATE DATABASE_DEFAULT))
      AND (@sc_filter IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@sc_filter, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = U.name COLLATE DATABASE_DEFAULT))
) AS src;

/* ===== #valid_common_type ===== */
SELECT *
INTO #valid_common_type
FROM (
SELECT T.tp_grp_1, T.common_tp_nm, MIN(O.tp_grp_1_order) AS grp_ord, MIN(O.tp_order) AS tp_ord
    FROM ktws.DIM_CRM_ACT_TYPE AS T
    LEFT JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS O ON T.common_tp_nm = O.common_tp_nm
    WHERE (NULLIF(LTRIM(RTRIM(@tp_grp_1)), N'') IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@tp_grp_1, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = T.tp_grp_1 COLLATE DATABASE_DEFAULT))
      AND (NULLIF(LTRIM(RTRIM(@common_tp_nm)), N'') IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@common_tp_nm, N',') AS X WHERE LTRIM(RTRIM(X.value)) COLLATE DATABASE_DEFAULT = O.common_tp_nm COLLATE DATABASE_DEFAULT))
    GROUP BY T.tp_grp_1, T.common_tp_nm
) AS src;

/* ===== #valid_group ===== */
SELECT *
INTO #valid_group
FROM (
SELECT tp_grp_1, MIN(grp_ord) AS grp_ord
    FROM #valid_common_type
    GROUP BY tp_grp_1
) AS src;

/* ===== #valid_type ===== */
SELECT *
INTO #valid_type
FROM (
SELECT DISTINCT T.tp_key, T.tp_cd, T.tp_grp_1, T.common_tp_nm
    FROM ktws.DIM_CRM_ACT_TYPE AS T
    INNER JOIN #valid_common_type AS VCT ON T.tp_grp_1 = VCT.tp_grp_1 AND T.common_tp_nm = VCT.common_tp_nm
) AS src;

/* ===== #scope_seed ===== */
SELECT *
INTO #scope_seed
FROM (
SELECT CAST(7 AS INT) AS scope_level, U.brand_nm, U.dealer_nm, U.group_name, U.dept_nm, U.sc_name, T.tp_grp_1, T.common_tp_nm, T.grp_ord, T.tp_ord
    FROM #valid_user AS U
    CROSS JOIN #valid_common_type AS T

    UNION ALL

    SELECT CAST(6 AS INT), U.brand_nm, U.dealer_nm, U.group_name, U.dept_nm, U.sc_name, G.tp_grp_1, CAST(NULL AS VARCHAR(500)), G.grp_ord, CAST(NULL AS INT)
    FROM #valid_user AS U
    CROSS JOIN #valid_group AS G

    UNION ALL

    SELECT CAST(5 AS INT), U.brand_nm, U.dealer_nm, U.group_name, U.dept_nm, U.sc_name, CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS INT), CAST(NULL AS INT)
    FROM #valid_user AS U

    UNION ALL

    SELECT DISTINCT CAST(4 AS INT), U.brand_nm, U.dealer_nm, U.group_name, U.dept_nm, CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS INT), CAST(NULL AS INT)
    FROM #valid_user AS U

    UNION ALL

    SELECT DISTINCT CAST(3 AS INT), U.brand_nm, U.dealer_nm, U.group_name, CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS INT), CAST(NULL AS INT)
    FROM #valid_user AS U

    UNION ALL

    SELECT DISTINCT CAST(2 AS INT), U.brand_nm, U.dealer_nm, CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS INT), CAST(NULL AS INT)
    FROM #valid_user AS U

    UNION ALL

    SELECT DISTINCT CAST(1 AS INT), U.brand_nm, CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS INT), CAST(NULL AS INT)
    FROM #valid_user AS U

    UNION ALL

    SELECT CAST(0 AS INT), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS VARCHAR(500)), CAST(NULL AS INT), CAST(NULL AS INT)
) AS src;

/* ===== #scope ===== */
SELECT *
INTO #scope
FROM (
SELECT ROW_NUMBER() OVER (ORDER BY scope_level, brand_nm, dealer_nm, group_name, dept_nm, sc_name, tp_grp_1, common_tp_nm) AS scope_id,
           scope_level, brand_nm, dealer_nm, group_name, dept_nm, sc_name, tp_grp_1, common_tp_nm, grp_ord, tp_ord
    FROM #scope_seed
) AS src;

/* ===== #scope_user ===== */
SELECT *
INTO #scope_user
FROM (
SELECT S.scope_id, U.sc_key
    FROM #scope AS S
    INNER JOIN #valid_user AS U
        ON (S.brand_nm IS NULL OR S.brand_nm = U.brand_nm)
       AND (S.dealer_nm IS NULL OR S.dealer_nm = U.dealer_nm)
       AND (S.group_name IS NULL OR S.group_name = U.group_name)
       AND (S.dept_nm IS NULL OR S.dept_nm = U.dept_nm)
       AND (S.sc_name IS NULL OR S.sc_name = U.sc_name)
) AS src;

/* ===== #scope_type ===== */
SELECT *
INTO #scope_type
FROM (
SELECT S.scope_id, T.tp_key
    FROM #scope AS S
    INNER JOIN #valid_type AS T
        ON (S.tp_grp_1 IS NULL OR S.tp_grp_1 = T.tp_grp_1)
       AND (S.common_tp_nm IS NULL OR S.common_tp_nm = T.common_tp_nm)
) AS src;

/* ===== #activity_actual ===== */
SELECT *
INTO #activity_actual
FROM (
SELECT SU.scope_id, SUM(ISNULL(A.actual_cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON SU.sc_key = A.sc_key
    INNER JOIN #scope_type AS ST ON SU.scope_id = ST.scope_id AND A.tp_key = ST.tp_key
    WHERE A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #activity_target ===== */
SELECT *
INTO #activity_target
FROM (
SELECT SU.scope_id, SUM(ISNULL(TG.target_cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CRM_TARGET_D AS TG ON SU.sc_key = TG.sc_key
    INNER JOIN #scope_type AS ST ON SU.scope_id = ST.scope_id AND TG.type_cd = ST.tp_key
    WHERE TG.daily_dt >= @month_start AND TG.daily_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #lead_activity_candidate ===== */
SELECT *
INTO #lead_activity_candidate
FROM (
SELECT DISTINCT ST.scope_id, A.lead_key
    FROM #scope_type AS ST
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON ST.tp_key = A.tp_key
    WHERE A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND A.act_result <> N'부재중'
      AND A.lead_key IS NOT NULL
) AS src;

/* ===== #lead_activity_set ===== */
SELECT *
INTO #lead_activity_set
FROM (
SELECT DISTINCT SU.scope_id, G.lead_key
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_LEAD AS G ON SU.sc_key = G.cl_sc_key
    INNER JOIN #lead_activity_candidate AS A ON SU.scope_id = A.scope_id AND G.lead_key = A.lead_key
    WHERE G.lead_reg_dt >= @month_start AND G.lead_reg_dt < DATEADD(DAY, 1, @as_of_date)
      AND (G.close_dt > @ref_date OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)
) AS src;

/* ===== #lead_activity_count ===== */
SELECT *
INTO #lead_activity_count
FROM (
SELECT scope_id, COUNT(DISTINCT lead_key) AS cnt
    FROM #lead_activity_set
    GROUP BY scope_id
) AS src;

/* ===== #lead_total_count ===== */
SELECT *
INTO #lead_total_count
FROM (
SELECT SU.scope_id, SUM(NULLIF(G.cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_LEAD AS G ON SU.sc_key = G.cl_sc_key
    INNER JOIN #scope AS S ON SU.scope_id = S.scope_id
    LEFT JOIN #scope_type AS ST ON SU.scope_id = ST.scope_id AND G.tp_key = ST.tp_key
    WHERE G.lead_reg_dt >= @month_start AND G.lead_reg_dt < DATEADD(DAY, 1, @as_of_date)
      AND (G.close_dt > @ref_date OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)
      AND (S.scope_level = 0 OR ST.tp_key IS NOT NULL)
    GROUP BY SU.scope_id
) AS src;

/* ===== #lead_target ===== */
SELECT *
INTO #lead_target
FROM (
SELECT SU.scope_id, SUM(ISNULL(TM.target_cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CRM_TARGET_M AS TM ON SU.sc_key = TM.sc_key
    INNER JOIN #scope_type AS ST ON SU.scope_id = ST.scope_id AND TM.tp_key = ST.tp_key
    WHERE TM.monthly_dt >= @month_start AND TM.monthly_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #contract_activity_count ===== */
SELECT *
INTO #contract_activity_count
FROM (
SELECT SU.scope_id, SUM(ISNULL(I.cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CONTRACT_KTWS AS I ON SU.sc_key = I.cn_sc_key
    INNER JOIN #lead_activity_set AS L ON SU.scope_id = L.scope_id AND I.lead_key = L.lead_key
    WHERE I.contract_dt >= @month_start AND I.contract_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #contract_total_count ===== */
SELECT *
INTO #contract_total_count
FROM (
SELECT SU.scope_id, SUM(ISNULL(I.cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CONTRACT_KTWS AS I ON SU.sc_key = I.cn_sc_key
    WHERE I.contract_dt >= @month_start AND I.contract_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #contract_target ===== */
SELECT *
INTO #contract_target
FROM (
SELECT SU.scope_id, SUM(ISNULL(TM.target_cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CRM_TARGET_M AS TM ON SU.sc_key = TM.sc_key
    INNER JOIN ktws.DIM_CRM_ACT_TYPE AS T ON TM.tp_key = T.tp_key
    WHERE T.common_tp_nm = N'계약'
      AND TM.monthly_dt >= @month_start AND TM.monthly_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #contract_progress_activity_candidate ===== */
SELECT *
INTO #contract_progress_activity_candidate
FROM (
SELECT DISTINCT SU.scope_id, A.lead_key
    FROM #scope_user AS SU
    INNER JOIN #scope AS S ON SU.scope_id = S.scope_id
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON SU.sc_key = A.sc_key
    INNER JOIN #scope_type AS ST ON SU.scope_id = ST.scope_id AND A.tp_key = ST.tp_key
    WHERE A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND (A.act_result <> N'부재중' OR A.act_result IS NULL)
      AND A.lead_key IS NOT NULL
      AND S.scope_level <> 0

    UNION

    SELECT DISTINCT S.scope_id, A.lead_key
    FROM #scope AS S
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON 1 = 1
    WHERE S.scope_level = 0
      AND A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND (A.act_result <> N'부재중' OR A.act_result IS NULL)
      AND A.lead_key IS NOT NULL
) AS src;

/* ===== #contract_progress_lead_set ===== */
SELECT *
INTO #contract_progress_lead_set
FROM (
SELECT DISTINCT SU.scope_id, G.lead_key
    FROM #scope_user AS SU
    INNER JOIN #scope AS S ON SU.scope_id = S.scope_id
    INNER JOIN ktws.FCT_LEAD AS G ON SU.sc_key = G.cl_sc_key
    INNER JOIN #contract_progress_activity_candidate AS A ON SU.scope_id = A.scope_id AND G.lead_key = A.lead_key
    WHERE G.lead_reg_dt >= @month_start AND G.lead_reg_dt < DATEADD(DAY, 1, @as_of_date)
      AND (G.close_dt > EOMONTH(@as_of_date) OR G.close_dt IS NULL)
      AND S.scope_level <> 0

    UNION

    SELECT DISTINCT S.scope_id, G.lead_key
    FROM #scope AS S
    INNER JOIN #contract_progress_activity_candidate AS A ON S.scope_id = A.scope_id
    INNER JOIN ktws.FCT_LEAD AS G ON A.lead_key = G.lead_key
    WHERE S.scope_level = 0
      AND G.lead_reg_dt >= @month_start AND G.lead_reg_dt < DATEADD(DAY, 1, @as_of_date)
      AND (G.close_dt > EOMONTH(@as_of_date) OR G.close_dt IS NULL)
) AS src;

/* ===== #contract_progress_count ===== */
SELECT *
INTO #contract_progress_count
FROM (
SELECT SU.scope_id, SUM(ISNULL(I.cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CONTRACT_KTWS AS I ON SU.sc_key = I.cn_sc_key
    INNER JOIN #contract_progress_lead_set AS L ON SU.scope_id = L.scope_id AND I.lead_key = L.lead_key
    WHERE I.contract_dt >= @month_start AND I.contract_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #td_activity_candidate ===== */
SELECT *
INTO #td_activity_candidate
FROM (
SELECT DISTINCT SU.scope_id, A.lead_key
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON SU.sc_key = A.sc_key
    INNER JOIN #scope_type AS ST ON SU.scope_id = ST.scope_id AND A.tp_key = ST.tp_key
    WHERE A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND (A.act_result <> N'부재중' OR A.act_result IS NULL)
      AND (A.contact_tp <> N'MSG' OR A.contact_tp IS NULL)
      AND A.lead_key IS NOT NULL
) AS src;

/* ===== #td_lead_set ===== */
SELECT *
INTO #td_lead_set
FROM (
SELECT DISTINCT SU.scope_id, G.lead_key
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_LEAD AS G ON SU.sc_key = G.cl_sc_key
    INNER JOIN #td_activity_candidate AS A ON SU.scope_id = A.scope_id AND G.lead_key = A.lead_key
    WHERE G.lead_reg_dt >= @month_start AND G.lead_reg_dt < DATEADD(DAY, 1, @as_of_date)
      AND (G.close_dt > @ref_date OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)
) AS src;

/* ===== #td_completed_lead_match ===== */
SELECT *
INTO #td_completed_lead_match
FROM (
SELECT SU.scope_id, COUNT(DISTINCT A.lead_key) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON SU.sc_key = A.sc_key
    INNER JOIN #td_lead_set AS L ON SU.scope_id = L.scope_id AND A.lead_key = L.lead_key
    WHERE A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND A.act_tp = N'P113'
      AND A.act_result = N'시승완료'
      AND A.lead_key IS NOT NULL
    GROUP BY SU.scope_id
) AS src;

/* ===== #td_form_without_cancel ===== */
SELECT *
INTO #td_form_without_cancel
FROM (
SELECT SU.scope_id, SUM(ISNULL(A.actual_cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON SU.sc_key = A.sc_key
    INNER JOIN #td_lead_set AS L ON SU.scope_id = L.scope_id AND A.lead_key = L.lead_key
    WHERE A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND A.act_tp = N'P113'
      AND (A.act_result <> N'시승취소' OR A.act_result IS NULL)
      AND A.lead_key IS NOT NULL
    GROUP BY SU.scope_id
) AS src;

/* ===== #lead_set_all_calendar ===== */
SELECT *
INTO #lead_set_all_calendar
FROM (
SELECT DISTINCT SU.scope_id, G.lead_key
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_LEAD AS G ON SU.sc_key = G.cl_sc_key
    INNER JOIN #scope AS S ON SU.scope_id = S.scope_id
    LEFT JOIN #scope_type AS ST ON SU.scope_id = ST.scope_id AND G.tp_key = ST.tp_key
    WHERE G.lead_key IS NOT NULL
      AND (S.scope_level = 0 OR ST.tp_key IS NOT NULL)
) AS src;

/* ===== #td_completed_total_lead_set ===== */
SELECT *
INTO #td_completed_total_lead_set
FROM (
SELECT DISTINCT SU.scope_id, A.lead_key
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON SU.sc_key = A.sc_key
    INNER JOIN #lead_set_all_calendar AS L ON SU.scope_id = L.scope_id AND A.lead_key = L.lead_key
    WHERE A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND A.act_tp = N'P113'
      AND A.act_result = N'시승완료'
      AND A.lead_key IS NOT NULL
) AS src;

/* ===== #td_total_lead_distinct ===== */
SELECT *
INTO #td_total_lead_distinct
FROM (
SELECT scope_id, COUNT(DISTINCT lead_key) AS cnt
    FROM #td_completed_total_lead_set
    GROUP BY scope_id
) AS src;

/* ===== #td_total_actual_sum ===== */
SELECT *
INTO #td_total_actual_sum
FROM (
SELECT SU.scope_id, SUM(ISNULL(A.actual_cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON SU.sc_key = A.sc_key
    INNER JOIN #lead_set_all_calendar AS L ON SU.scope_id = L.scope_id AND A.lead_key = L.lead_key
    WHERE A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND A.act_tp = N'P113'
      AND A.act_result = N'시승완료'
      AND A.lead_key IS NOT NULL
    GROUP BY SU.scope_id
) AS src;

/* ===== #td_target ===== */
SELECT *
INTO #td_target
FROM (
SELECT SU.scope_id, SUM(ISNULL(TD.target_cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CRM_TARGET_D AS TD ON SU.sc_key = TD.sc_key
    INNER JOIN ktws.DIM_CRM_ACT_TYPE AS T ON TD.type_cd = T.tp_key
    WHERE T.tp_cd = N'P113'
      AND TD.daily_dt >= @month_start AND TD.daily_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #contract_td_lead_set ===== */
SELECT *
INTO #contract_td_lead_set
FROM (
SELECT DISTINCT L.scope_id, G.lead_key
    FROM #lead_activity_set AS L
    INNER JOIN #scope AS S ON L.scope_id = S.scope_id
    INNER JOIN ktws.FCT_LEAD AS G ON L.lead_key = G.lead_key
    WHERE S.scope_level <> 0
      AND G.td_yn = N'Y'
      AND G.lead_reg_dt >= @month_start AND G.lead_reg_dt < DATEADD(DAY, 1, @as_of_date)
      AND (G.close_dt > @ref_date OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)

    UNION

    SELECT DISTINCT S.scope_id, G.lead_key
    FROM #scope AS S
    INNER JOIN #scope_user AS GSU ON S.scope_id = GSU.scope_id
    INNER JOIN ktws.FCT_LEAD AS G ON GSU.sc_key = G.cl_sc_key
    INNER JOIN ktws.FCT_ACTIVITY_v2 AS A ON G.lead_key = A.lead_key
    INNER JOIN #valid_user AS AU ON A.sc_key = AU.sc_key
    INNER JOIN #scope_type AS ST ON S.scope_id = ST.scope_id AND A.tp_key = ST.tp_key
    WHERE S.scope_level = 0
      AND G.td_yn = N'Y'
      AND G.lead_reg_dt >= @month_start AND G.lead_reg_dt < DATEADD(DAY, 1, @as_of_date)
      AND A.act_dt_fr >= @month_start AND A.act_dt_fr < DATEADD(DAY, 1, @as_of_date)
      AND A.act_result <> N'부재중'
      AND A.lead_key IS NOT NULL
      AND (G.close_dt > @ref_date OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)
) AS src;

/* ===== #contract_td_activity_count ===== */
SELECT *
INTO #contract_td_activity_count
FROM (
SELECT SU.scope_id, SUM(ISNULL(I.cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CONTRACT_KTWS AS I ON SU.sc_key = I.cn_sc_key
    INNER JOIN #contract_td_lead_set AS L ON SU.scope_id = L.scope_id AND I.lead_key = L.lead_key
    WHERE I.contract_dt >= @month_start AND I.contract_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
) AS src;

/* ===== #contract_td_total_count ===== */
SELECT *
INTO #contract_td_total_count
FROM (
SELECT SU.scope_id, SUM(ISNULL(I.cnt, 0)) AS cnt
    FROM #scope_user AS SU
    INNER JOIN ktws.FCT_CONTRACT_KTWS AS I ON SU.sc_key = I.cn_sc_key
    INNER JOIN #td_completed_total_lead_set AS L ON SU.scope_id = L.scope_id AND I.lead_key = L.lead_key
    WHERE I.contract_dt >= @month_start AND I.contract_dt < DATEADD(DAY, 1, @as_of_date)
    GROUP BY SU.scope_id
