/* ===== #metric_raw ===== */
SELECT *
INTO #metric_raw
FROM (
SELECT S.scope_level, S.brand_nm, S.dealer_nm, S.group_name, S.dept_nm, S.sc_name, S.tp_grp_1, S.common_tp_nm, S.grp_ord, S.tp_ord,
           CAST(COALESCE(AA.cnt, 0) AS BIGINT) AS [영업활동 건 수],
           CAST(COALESCE(AT.cnt, 0) AS BIGINT) AS [영업활동 당월 목표],
           CAST(COALESCE(LAC.cnt, 0) AS BIGINT) AS [영업기회 건 수(당월활동실적)],
           CAST(COALESCE(LTC.cnt, 0) AS BIGINT) AS [영업기회 건 수(당월전체실적)],
           CAST(COALESCE(LT.cnt, 0) AS BIGINT) AS [영업기회 당월 목표],
           CAST(COALESCE(CAC.cnt, 0) AS BIGINT) AS [계약건수(당월활동실적)],
           CAST(COALESCE(CTC.cnt, 0) AS BIGINT) AS [계약건수(당월전체실적)],
           CAST(COALESCE(CT.cnt, 0) AS BIGINT) AS [계약 당월 목표],
           CAST(COALESCE(CPC.cnt, 0) AS BIGINT) AS [계약 진행 실적],
           CAST(COALESCE(TDCLM.cnt, 0) AS BIGINT) AS [시승건수(당월활동실적/시승완료)],
           CAST(COALESCE(TDFC.cnt, 0) AS BIGINT) AS [시승건수(당월활동실적/시승취소건 제외)],
           CAST(COALESCE(TDTLD.cnt, 0) AS BIGINT) AS [시승건수(당월전체실적/lead_key 기준)],
           CAST(COALESCE(TDTAS.cnt, 0) AS BIGINT) AS [시승건수(당월전체실적/actual_cnt 기준)],
           CAST(COALESCE(TDT.cnt, 0) AS BIGINT) AS [시승 당월 목표],
           CAST(COALESCE(CTDAC.cnt, 0) AS BIGINT) AS [시승에서 계약으로 당월활동실적],
           CAST(COALESCE(CTDTC.cnt, 0) AS BIGINT) AS [시승에서 계약으로 당월전체실적]
    FROM #scope AS S
    LEFT JOIN #activity_actual AS AA ON S.scope_id = AA.scope_id
    LEFT JOIN #activity_target AS AT ON S.scope_id = AT.scope_id
    LEFT JOIN #lead_activity_count AS LAC ON S.scope_id = LAC.scope_id
    LEFT JOIN #lead_total_count AS LTC ON S.scope_id = LTC.scope_id
    LEFT JOIN #lead_target AS LT ON S.scope_id = LT.scope_id
    LEFT JOIN #contract_activity_count AS CAC ON S.scope_id = CAC.scope_id
    LEFT JOIN #contract_total_count AS CTC ON S.scope_id = CTC.scope_id
    LEFT JOIN #contract_target AS CT ON S.scope_id = CT.scope_id
    LEFT JOIN #contract_progress_count AS CPC ON S.scope_id = CPC.scope_id
    LEFT JOIN #td_completed_lead_match AS TDCLM ON S.scope_id = TDCLM.scope_id
    LEFT JOIN #td_form_without_cancel AS TDFC ON S.scope_id = TDFC.scope_id
    LEFT JOIN #td_total_lead_distinct AS TDTLD ON S.scope_id = TDTLD.scope_id
    LEFT JOIN #td_total_actual_sum AS TDTAS ON S.scope_id = TDTAS.scope_id
    LEFT JOIN #td_target AS TDT ON S.scope_id = TDT.scope_id
    LEFT JOIN #contract_td_activity_count AS CTDAC ON S.scope_id = CTDAC.scope_id
    LEFT JOIN #contract_td_total_count AS CTDTC ON S.scope_id = CTDTC.scope_id
) AS src;

SELECT CASE WHEN brand_nm IS NULL THEN N'전체' ELSE brand_nm END AS [브랜드],
       CASE WHEN dealer_nm IS NULL THEN N'전체' ELSE dealer_nm END AS [딜러],
       CASE WHEN group_name IS NULL THEN N'전체' ELSE group_name END AS [전시장],
       CASE WHEN dept_nm IS NULL THEN N'전체' ELSE dept_nm END AS [팀],
       CASE WHEN sc_name IS NULL THEN N'전체' ELSE sc_name END AS [SC],
       CASE WHEN tp_grp_1 IS NULL THEN N'전체' ELSE tp_grp_1 END AS [활동유형분류],
       CASE WHEN common_tp_nm IS NULL THEN N'전체' ELSE common_tp_nm END AS [활동유형],
       [영업활동 건 수],
       [영업활동 당월 목표],
       FORMAT(CASE WHEN [영업활동 당월 목표] = 0 THEN CAST(0 AS DECIMAL(38, 10)) ELSE CAST([영업활동 건 수] AS DECIMAL(38, 10)) / CAST([영업활동 당월 목표] AS DECIMAL(38, 10)) END, '0.00%') AS [영업활동 진행률],
       FORMAT(CASE WHEN [영업활동 건 수] = 0 THEN CAST(0 AS DECIMAL(38, 10)) ELSE CAST([영업기회 건 수(당월활동실적)] AS DECIMAL(38, 10)) / CAST([영업활동 건 수] AS DECIMAL(38, 10)) END, '0.00%') AS [영업활동에서 영업기회로의 전환율],
       [영업기회 건 수(당월활동실적)],
       [영업기회 건 수(당월전체실적)],
       [영업기회 당월 목표],
       FORMAT(CASE WHEN [영업기회 당월 목표] = 0 THEN CAST(0 AS DECIMAL(38, 10)) ELSE CAST([영업기회 건 수(당월활동실적)] AS DECIMAL(38, 10)) / CAST([영업기회 당월 목표] AS DECIMAL(38, 10)) END, '0.00%') AS [영업기회 진행률],
       FORMAT(CASE WHEN [영업기회 건 수(당월활동실적)] = 0 THEN CAST(0 AS DECIMAL(38, 10)) ELSE CAST([계약건수(당월활동실적)] AS DECIMAL(38, 10)) / CAST([영업기회 건 수(당월활동실적)] AS DECIMAL(38, 10)) END, '0.00%') AS [영업기회에서 계약으로 전환율],
       [계약건수(당월활동실적)],
       [계약건수(당월전체실적)],
       [계약 당월 목표],
       FORMAT(CASE WHEN [계약 당월 목표] = 0 THEN CAST(0 AS DECIMAL(38, 10)) ELSE CAST([계약 진행 실적] AS DECIMAL(38, 10)) / CAST([계약 당월 목표] AS DECIMAL(38, 10)) END, '0.00%') AS [계약 진행률],
       FORMAT(CASE WHEN [영업기회 건 수(당월활동실적)] = 0 THEN CAST(0 AS DECIMAL(38, 10)) ELSE CAST([시승건수(당월활동실적/시승완료)] AS DECIMAL(38, 10)) / CAST([영업기회 건 수(당월활동실적)] AS DECIMAL(38, 10)) END, '0.00%') AS [영업기회에서 시승으로 전환율],
       [시승건수(당월활동실적/시승완료)],
       [시승건수(당월활동실적/시승취소건 제외)],
       [시승건수(당월전체실적/lead_key 기준)],
       [시승건수(당월전체실적/actual_cnt 기준)],
       [시승 당월 목표],
       FORMAT(CASE WHEN [시승 당월 목표] = 0 THEN CAST(0 AS DECIMAL(38, 10)) ELSE CAST([시승건수(당월전체실적/actual_cnt 기준)] AS DECIMAL(38, 10)) / CAST([시승 당월 목표] AS DECIMAL(38, 10)) END, '0.00%') AS [시승 진행률],
       FORMAT(CASE WHEN [시승건수(당월활동실적/시승완료)] = 0 THEN CAST(0 AS DECIMAL(38, 10)) ELSE CAST([시승에서 계약으로 당월활동실적] AS DECIMAL(38, 10)) / CAST([시승건수(당월활동실적/시승완료)] AS DECIMAL(38, 10)) END, '0.00%') AS [시승에서 계약으로 전환율],
       [시승에서 계약으로 당월활동실적],
       [시승에서 계약으로 당월전체실적]
FROM #metric_raw
ORDER BY scope_level, brand_nm, dealer_nm, group_name, dept_nm, sc_name, grp_ord, tp_ord, tp_grp_1, common_tp_nm;

/* ══════════════════════════════════════════════════════════════════════════
   [목표 저장 현황] — 선택 월(@base_month) 기준 SC별 목표저장 여부 (Y/N)
   ──────────────────────────────────────────────────────────────────────────
   grain : SC 1명당 1행. (활동유형·N개월 평균과 무관 → 퍼널 쿼리와 분리)
   용도  : 도넛(저장여부별 SC 수) / 저장현황 목록 테이블 겸용.
   기준  : FCT_CRM_TARGET_STS, ym = @base_month. save_yn='Y' 하나라도 있으면 Y.
   슬라이서/제외 : 퍼널·목표관리 쿼리와 동일 규칙.
   ══════════════════════════════════════════════════════════════════════════ */

/* ── 기준월 (연도/월 슬라이서 → 그대로 매핑) ── */
DECLARE @year  INT = 2026;
DECLARE @month INT = 1;
DECLARE @base_month DATE = DATEFROMPARTS(@year, @month, 1);

/* ── 슬라이서 (NULL=모두, 콤마 다중) ── */
DECLARE @brand       NVARCHAR(MAX) = NULL;
DECLARE @dealer_nm   NVARCHAR(MAX) = NULL;
DECLARE @group_name  NVARCHAR(MAX) = NULL;
DECLARE @dept_nm     NVARCHAR(MAX) = NULL;
DECLARE @active_yn   NVARCHAR(MAX) = N'재직';
DECLARE @sc_name     NVARCHAR(MAX) = '강민석, 강민성';   -- 저장현황은 보통 전체 SC. 특정 SC만 볼 땐 지정.

/* ── 제외 규칙 ── */
DECLARE @exclude_facade NVARCHAR(50)  = N'창구SC';
DECLARE @exclude_dept   NVARCHAR(MAX) = N'고객지원팀,TOYOTA YM';
DECLARE @exclude_users  NVARCHAR(MAX) = N'DM5103,DM9999,JB30007,JB30016,KMKS176,KMKS999,JB30067';

;WITH
/* ── 슬라이서·제외 통과 SC (계층 컬럼 포함) ── */
elig_user AS (
    SELECT u.sc_key, u.[name] AS sc_name, u.dept_nm, u.group_name, dlr.dealer_nm
    FROM   ktws.DIM_MNG_USER u
    LEFT JOIN ktws.DIM_MNG_DEALER dlr ON u.dealer_key = dlr.dealer_key
    WHERE  ISNULL(u.facade_sc_yn,N'') <> @exclude_facade
      AND (@brand      IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@brand,     N',') x WHERE LTRIM(RTRIM(x.value)) = u.BRAND))
      AND (@dealer_nm  IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@dealer_nm, N',') x WHERE LTRIM(RTRIM(x.value)) = dlr.dealer_nm))
      AND (@group_name IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@group_name,N',') x WHERE LTRIM(RTRIM(x.value)) = u.group_name))
      AND (@dept_nm    IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@dept_nm,   N',') x WHERE LTRIM(RTRIM(x.value)) = u.dept_nm))
      AND (@active_yn  IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@active_yn, N',') x WHERE LTRIM(RTRIM(x.value)) = u.active_yn))
      AND (@sc_name    IS NULL OR EXISTS (SELECT 1 FROM STRING_SPLIT(@sc_name,   N',') x WHERE LTRIM(RTRIM(x.value)) = u.name))
      AND NOT EXISTS (SELECT 1 FROM STRING_SPLIT(@exclude_dept,',') s WHERE LTRIM(RTRIM(s.value)) = u.dept_nm)
      AND NOT EXISTS (SELECT 1 FROM STRING_SPLIT(@exclude_users,',') s WHERE LTRIM(RTRIM(s.value)) = u.user_id)
),
/* ── @base_month STS : SC별 저장여부 ── */
sc_save AS (
    SELECT f.sc_key,
           MAX(CASE WHEN f.save_yn = N'Y' THEN 1 ELSE 0 END) AS saved  -- 하나라도 Y면 1
    FROM ktws.FCT_CRM_TARGET_STS f
    WHERE f.ym = @base_month
    GROUP BY f.sc_key
)
/* ── 출력 : SC 1행. STS 없으면 '미저장'(N)으로 표기 ──
      · 도넛  : [목표저장여부] 로 그룹, SC 수(COUNT) 또는 [저장플래그] 합/평균
      · 목록  : 그대로 테이블. 딜러/전시장/부서/SC/저장여부                       */
SELECT
    eu.dealer_nm  AS [딜러],
    eu.group_name AS [전시장],
    eu.dept_nm    AS [부서],
    eu.sc_name    AS [SC],
    CASE WHEN ISNULL(sv.saved,0)=1 THEN N'Y' ELSE N'N' END AS [목표저장여부],
    ISNULL(sv.saved,0) AS [저장플래그]   -- 1=저장, 0=미저장 (도넛 수치용)
FROM elig_user eu
LEFT JOIN sc_save sv ON sv.sc_key = eu.sc_key
ORDER BY [목표저장여부] DESC, [딜러], [전시장], [부서], [SC];
